// Auto-generated — galatas (NVI)
// Do NOT edit manually. Re-run scripts/download-bible.mjs to update.

export const GALATAS_NVI: Record<number, string[]> = {
  1: ["Pablo, apóstol, no por investidura ni mediación humanas, sino por Jesucristo y por Dios Padre, que lo levantó de entre los muertos;","y todos los hermanos que están conmigo, a las iglesias de Galacia:","Que Dios nuestro Padre y el Señor Jesucristo les concedan gracia y paz.","Jesucristo dio su vida por nuestros pecados para rescatarnos de este mundo malvado, según la voluntad de nuestro Dios y Padre,","a quien sea la gloria por los siglos de los siglos. Amén.","Me asombra que tan pronto estén dejando ustedes a quien los llamó por la gracia de Cristo, para pasarse a otro evangelio.","No es que haya otro evangelio, sino que ciertos individuos están sembrando confusión entre ustedes y quieren tergiversar el evangelio de Cristo.","Pero, aun si alguno de nosotros o un ángel del cielo les predicara un evangelio distinto del que les hemos predicado, ¡que caiga bajo maldición!","Como ya lo hemos dicho, ahora lo repito: si alguien les anda predicando un evangelio distinto del que recibieron, ¡que caiga bajo maldición!","¿Qué busco con esto: ganarme la aprobación humana o la de Dios? ¿Piensan que procuro agradar a los demás? Si yo buscara agradar a otros, no sería siervo de Cristo.","Quiero que sepan, hermanos, que el evangelio que yo predico no es invención humana.","No lo recibí ni lo aprendí de ningún ser humano, sino que me llegó por revelación de Jesucristo.","Ustedes ya están enterados de mi conducta cuando pertenecía al judaísmo, de la furia con que perseguía a la iglesia de Dios, tratando de destruirla.","En la práctica del judaísmo, yo aventajaba a muchos de mis contemporáneos en mi celo exagerado por las tradiciones de mis antepasados.","Sin embargo, Dios me había apartado desde el vientre de mi madre y me llamó por su gracia. Y, cuando él tuvo a bien","revelarme a su Hijo para que yo lo predicara entre los gentiles, no consulté con nadie.","Tampoco subí a Jerusalén para ver a los que eran apóstoles antes que yo, sino que fui de inmediato a Arabia, de donde luego regresé a Damasco.","Después de tres años, subí a Jerusalén para visitar a Pedro,[1] y me quedé con él quince días.","No vi a ningún otro de los apóstoles; solo vi a Jacobo, el hermano del Señor.","Dios me es testigo de que en esto que les escribo no miento.","Más tarde fui a las regiones de Siria y Cilicia.","Pero en Judea las iglesias de[2] Cristo no me conocían personalmente.","Solo habían oído decir: «El que antes nos perseguía ahora predica la fe que procuraba destruir».","Y por causa mía glorificaban a Dios."],
  2: ["Catorce años después subí de nuevo a Jerusalén, esta vez con Bernabé, llevando también a Tito.","Fui en obediencia a una revelación, y me reuní en privado con los que eran reconocidos como dirigentes, y les expliqué el evangelio que predico entre los gentiles, para que todo mi esfuerzo no fuera en vano.[3]","Ahora bien, ni siquiera Tito, que me acompañaba, fue obligado a circuncidarse, aunque era griego.","El problema era que algunos falsos hermanos se habían infiltrado entre nosotros para coartar la libertad que tenemos en Cristo Jesús a fin de esclavizarnos.","Ni por un momento accedimos a someternos a ellos, pues queríamos que se preservara entre ustedes la integridad del evangelio.","En cuanto a los que eran reconocidos como personas importantes —aunque no me interesa lo que fueran, porque Dios no juzga por las apariencias—, esos tales no me impusieron nada nuevo.","Al contrario, reconocieron que a mí se me había encomendado predicar el evangelio a los gentiles, de la misma manera que se le había encomendado a Pedro predicarlo a los judíos.[4]","El mismo Dios que facultó a Pedro como apóstol de los judíos[5] me facultó también a mí como apóstol de los gentiles.","En efecto, Jacobo, Pedro y Juan, que eran considerados columnas, al reconocer la gracia que yo había recibido, nos dieron la mano a Bernabé y a mí en señal de compañerismo, de modo que nosotros fuéramos a los gentiles y ellos a los judíos.","Solo nos pidieron que nos acordáramos de los pobres, y eso es precisamente lo que he venido haciendo con esmero.","Pues bien, cuando Pedro fue a Antioquía, le eché en cara su comportamiento condenable.","Antes que llegaran algunos de parte de Jacobo, Pedro solía comer con los gentiles. Pero, cuando aquellos llegaron, comenzó a retraerse y a separarse de los gentiles por temor a los partidarios de la circuncisión.[6]","Entonces los demás judíos se unieron a Pedro en su hipocresía, y hasta el mismo Bernabé se dejó arrastrar por esa conducta hipócrita.","Cuando vi que no actuaban rectamente, como corresponde a la integridad del evangelio, le dije a Pedro delante de todos: «Si tú, que eres judío, vives como si no lo fueras, ¿por qué obligas a los gentiles a practicar el judaísmo?","»Nosotros somos judíos de nacimiento y no “pecadores paganos”.","Sin embargo, al reconocer que nadie es justificado por las obras que demanda la ley, sino por la fe en Jesucristo, también nosotros hemos puesto nuestra fe en Cristo Jesús, para ser justificados por la fe en él y no por las obras de la ley; porque por estas nadie será justificado.","»Ahora bien, cuando buscamos ser justificados por[7] Cristo, se hace evidente que nosotros mismos somos pecadores. ¿Quiere esto decir que Cristo está al servicio del pecado? ¡De ninguna manera!","Si uno vuelve a edificar lo que antes había destruido, se hace[8] transgresor.","Yo, por mi parte, mediante la ley he muerto a la ley, a fin de vivir para Dios.","He sido crucificado con Cristo, y ya no vivo yo, sino que Cristo vive en mí. Lo que ahora vivo en el cuerpo, lo vivo por la fe en el Hijo de Dios, quien me amó y dio su vida por mí.","No desecho la gracia de Dios. Si la justicia se obtuviera mediante la ley, Cristo habría muerto en vano».[9]"],
  3: ["¡Gálatas torpes! ¿Quién los ha hechizado a ustedes, ante quienes Jesucristo crucificado ha sido presentado tan claramente?","Solo quiero que me respondan a esto: ¿Recibieron el Espíritu por las obras que demanda la ley, o por la fe con que aceptaron el mensaje?","¿Tan torpes son? Después de haber comenzado con el Espíritu, ¿pretenden ahora perfeccionarse con esfuerzos humanos?[10]","¿Tanto sufrir, para nada?[11] ¡Si es que de veras fue para nada!","Al darles Dios su Espíritu y hacer milagros entre ustedes, ¿lo hace por las obras que demanda la ley o por la fe con que han aceptado el mensaje?","Así fue con Abraham: «Le creyó a Dios, y esto se le tomó en cuenta como justicia».[12]","Por lo tanto, sepan que los descendientes de Abraham son aquellos que viven por la fe.","En efecto, la Escritura, habiendo previsto que Dios justificaría por la fe a las naciones, anunció de antemano el evangelio a Abraham: «Por medio de ti serán bendecidas todas las naciones».[13]","Así que los que viven por la fe son bendecidos junto con Abraham, el hombre de fe.","Todos los que viven por las obras que demanda la ley están bajo maldición, porque está escrito: «Maldito sea quien no practique fielmente todo lo que está escrito en el libro de la ley».[14]","Ahora bien, es evidente que por la ley nadie es justificado delante de Dios, porque «el justo vivirá por la fe».[15]","La ley no se basa en la fe; por el contrario, «quien practique estas cosas vivirá por ellas».[16]","Cristo nos rescató de la maldición de la ley al hacerse maldición por nosotros, pues está escrito: «Maldito todo el que es colgado de un madero».[17]","Así sucedió, para que, por medio de Cristo Jesús, la bendición prometida a Abraham llegara a las naciones, y para que por la fe recibiéramos el Espíritu según la promesa.","Hermanos, voy a ponerles un ejemplo: aun en el caso de un pacto[18] humano, nadie puede anularlo ni añadirle nada una vez que ha sido ratificado.","Ahora bien, las promesas se le hicieron a Abraham y a su descendencia. La Escritura no dice: «y a los descendientes», como refiriéndose a muchos, sino: «y a tu descendencia»,[19] dando a entender uno solo, que es Cristo.","Lo que quiero decir es esto: La ley, que vino cuatrocientos treinta años después, no anula el pacto que Dios había ratificado previamente; de haber sido así, quedaría sin efecto la promesa.","Si la herencia se basa en la ley, ya no se basa en la promesa; pero Dios se la concedió gratuitamente a Abraham mediante una promesa.","Entonces, ¿cuál era el propósito de la ley? Fue añadida por causa de[20] las transgresiones hasta que viniera la descendencia a la cual se hizo la promesa. La ley se promulgó por medio de ángeles, por conducto de un mediador.","Ahora bien, no hace falta mediador si hay una sola parte, y sin embargo Dios es uno solo.","Si esto es así, ¿estará la ley en contra de las promesas de Dios? ¡De ninguna manera! Si se hubiera promulgado una ley capaz de dar vida, entonces sí que la justicia se basaría en la ley.","Pero la Escritura declara que todo el mundo es prisionero del pecado,[21] para que mediante la fe en Jesucristo lo prometido se les conceda a los que creen.","Antes de venir esta fe, la ley nos tenía presos, encerrados hasta que la fe se revelara.","Así que la ley vino a ser nuestro guía encargado de conducirnos a Cristo,[22] para que fuéramos justificados por la fe.","Pero, ahora que ha llegado la fe, ya no estamos sujetos al guía.","Todos ustedes son hijos de Dios mediante la fe en Cristo Jesús,","porque todos los que han sido bautizados en Cristo se han revestido de Cristo.","Ya no hay judío ni griego, esclavo ni libre, hombre ni mujer, sino que todos ustedes son uno solo en Cristo Jesús.","Y, si ustedes pertenecen a Cristo, son la descendencia de Abraham y herederos según la promesa."],
  4: ["En otras palabras, mientras el heredero es menor de edad, en nada se diferencia de un esclavo, a pesar de ser dueño de todo.","Al contrario, está bajo el cuidado de tutores y administradores hasta la fecha fijada por su padre.","Así también nosotros, cuando éramos menores, estábamos esclavizados por los principios[23] de este mundo.","Pero, cuando se cumplió el plazo,[24] Dios envió a su Hijo, nacido de una mujer, nacido bajo la ley,","para rescatar a los que estaban bajo la ley, a fin de que fuéramos adoptados como hijos.","Ustedes ya son hijos. Dios ha enviado a nuestros corazones el Espíritu de su Hijo, que clama: «¡Abba! ¡Padre!»","Así que ya no eres esclavo, sino hijo; y, como eres hijo, Dios te ha hecho también heredero.","Antes, cuando no conocían a Dios, ustedes eran esclavos de los que en realidad no son dioses.","Pero, ahora que conocen a Dios —o más bien que Dios los conoce a ustedes—, ¿cómo es que quieren regresar a esos principios ineficaces y sin valor? ¿Quieren volver a ser esclavos de ellos?","¡Ustedes siguen guardando los días de fiesta, meses, estaciones y años!","Temo por ustedes, que tal vez me haya estado esforzando en vano.","Hermanos, yo me he identificado con ustedes. Les suplico que ahora se identifiquen conmigo. No es que me hayan ofendido en algo.","Como bien saben, la primera vez que les prediqué el evangelio fue debido a una enfermedad,","y, aunque esta fue una prueba para ustedes, no me trataron con desprecio ni desdén. Al contrario, me recibieron como a un ángel de Dios, como si se tratara de Cristo Jesús.","Pues bien, ¿qué pasó con todo ese entusiasmo? Me consta que, de haberles sido posible, se habrían sacado los ojos para dármelos.","¡Y ahora resulta que por decirles la verdad me he vuelto su enemigo!","Esos que muestran mucho interés por ganárselos a ustedes no abrigan buenas intenciones. Lo que quieren es alejarlos de nosotros para que ustedes se entreguen a ellos.","Está bien mostrar interés, con tal de que ese interés sea bien intencionado y constante, y que no se manifieste solo cuando yo estoy con ustedes.","Queridos hijos, por quienes vuelvo a sufrir dolores de parto hasta que Cristo sea formado en ustedes,","¡cómo quisiera estar ahora con ustedes y hablarles de otra manera, porque lo que están haciendo me tiene perplejo!","Díganme ustedes, los que quieren estar bajo la ley: ¿por qué no le prestan atención a lo que la ley misma dice?","¿Acaso no está escrito que Abraham tuvo dos hijos, uno de la esclava y otro de la libre?","El de la esclava nació por decisión humana, pero el de la libre nació en cumplimiento de una promesa.","Ese relato puede interpretarse en sentido figurado: estas mujeres representan dos pactos. Uno, que es Agar, procede del monte Sinaí y tiene hijos que nacen para ser esclavos.","Agar representa el monte Sinaí en Arabia, y corresponde a la actual ciudad de Jerusalén, porque junto con sus hijos vive en esclavitud.","Pero la Jerusalén celestial es libre, y esa es nuestra madre.","Porque está escrito: «Tú, mujer estéril que nunca has dado a luz, ¡grita de alegría! Tú, que nunca tuviste dolores de parto, ¡prorrumpe en gritos de júbilo! Porque más hijos que la casada tendrá la desamparada».[25]","Ustedes, hermanos, al igual que Isaac, son hijos por la promesa.","Y así como en aquel tiempo el hijo nacido por decisión humana persiguió al hijo nacido por el Espíritu, así también sucede ahora.","Pero ¿qué dice la Escritura? «¡Echa de aquí a la esclava y a su hijo! El hijo de la esclava jamás tendrá parte en la herencia con el hijo de la libre».[26]","Así que, hermanos, no somos hijos de la esclava, sino de la libre."],
  5: ["Cristo nos libertó para que vivamos en libertad. Por lo tanto, manténganse firmes[27] y no se sometan nuevamente al yugo de esclavitud.","Escuchen bien: yo, Pablo, les digo que, si se hacen circuncidar, Cristo no les servirá de nada.","De nuevo declaro que todo el que se hace circuncidar está obligado a practicar toda la ley.","Aquellos de entre ustedes que tratan de ser justificados por la ley han roto con Cristo; han caído de la gracia.","Nosotros, en cambio, por obra del Espíritu y mediante la fe, aguardamos con ansias la justicia que es nuestra esperanza.","En Cristo Jesús de nada vale estar o no estar circuncidados; lo que vale es la fe que actúa mediante el amor.","Ustedes estaban corriendo bien. ¿Quién los estorbó para que dejaran de obedecer a la verdad?","Tal instigación no puede venir de Dios, que es quien los ha llamado.","«Un poco de levadura fermenta toda la masa».","Yo por mi parte confío en el Señor que ustedes no pensarán de otra manera. El que los está perturbando será castigado, sea quien sea.","Hermanos, si es verdad que yo todavía predico la circuncisión, ¿por qué se me sigue persiguiendo? Si tal fuera mi predicación, la cruz no ofendería tanto.","¡Ojalá que esos instigadores acabaran por mutilarse del todo!","Les hablo así, hermanos, porque ustedes han sido llamados a ser libres; pero no se valgan de esa libertad para dar rienda suelta a sus pasiones. Más bien sírvanse unos a otros con amor.","En efecto, toda la ley se resume en un solo mandamiento: «Ama a tu prójimo como a ti mismo».[28]","Pero, si siguen mordiéndose y devorándose, tengan cuidado, no sea que acaben por destruirse unos a otros.","Así que les digo: Vivan por el Espíritu, y no seguirán los deseos de la naturaleza pecaminosa.","Porque esta desea lo que es contrario al Espíritu, y el Espíritu desea lo que es contrario a ella. Los dos se oponen entre sí, de modo que ustedes no pueden hacer lo que quieren.","Pero, si los guía el Espíritu, no están bajo la ley.","Las obras de la naturaleza pecaminosa se conocen bien: inmoralidad sexual, impureza y libertinaje;","idolatría y brujería; odio, discordia, celos, arrebatos de ira, rivalidades, disensiones, sectarismos","y envidia; borracheras, orgías, y otras cosas parecidas. Les advierto ahora, como antes lo hice, que los que practican tales cosas no heredarán el reino de Dios.","En cambio, el fruto del Espíritu es amor, alegría, paz, paciencia, amabilidad, bondad, fidelidad,","humildad y dominio propio. No hay ley que condene estas cosas.","Los que son de Cristo Jesús han crucificado la naturaleza pecaminosa, con sus pasiones y deseos.","Si el Espíritu nos da vida, andemos guiados por el Espíritu.","No dejemos que la vanidad nos lleve a irritarnos y a envidiarnos unos a otros."],
  6: ["Hermanos, si alguien es sorprendido en pecado, ustedes que son espirituales deben restaurarlo con una actitud humilde. Pero cuídese cada uno, porque también puede ser tentado.","Ayúdense unos a otros a llevar sus cargas, y así cumplirán la ley de Cristo.","Si alguien cree ser algo, cuando en realidad no es nada, se engaña a sí mismo.","Cada cual examine su propia conducta; y, si tiene algo de qué presumir, que no se compare con nadie.","Que cada uno cargue con su propia responsabilidad.","El que recibe instrucción en la palabra de Dios comparta todo lo bueno con quien le enseña.","No se engañen: de Dios nadie se burla. Cada uno cosecha lo que siembra.","El que siembra para agradar a su naturaleza pecaminosa, de esa misma naturaleza cosechará destrucción; el que siembra para agradar al Espíritu, del Espíritu cosechará vida eterna.","No nos cansemos de hacer el bien, porque a su debido tiempo cosecharemos si no nos damos por vencidos.","Por lo tanto, siempre que tengamos la oportunidad, hagamos bien a todos, y en especial a los de la familia de la fe.","Miren que les escribo de mi puño y letra, ¡y con letras bien grandes!","Los que tratan de obligarlos a ustedes a circuncidarse lo hacen únicamente para dar una buena impresión y evitar ser perseguidos por causa de la cruz de Cristo.","Ni siquiera esos que están circuncidados obedecen la ley; lo que pasa es que quieren obligarlos a ustedes a circuncidarse para luego jactarse de la señal que ustedes llevarían en el cuerpo.[29]","En cuanto a mí, jamás se me ocurra jactarme de otra cosa sino de la cruz de nuestro Señor Jesucristo, por quien[30] el mundo ha sido crucificado para mí, y yo para el mundo.","Para nada cuenta estar o no estar circuncidados; lo que importa es ser parte de una nueva creación.","Paz y misericordia desciendan sobre todos los que siguen esta norma, y sobre el Israel de Dios.","Por lo demás, que nadie me cause más problemas, porque yo llevo en el cuerpo las cicatrices de Jesús.","Hermanos, que la gracia de nuestro Señor Jesucristo sea con el espíritu de cada uno de ustedes. Amén."],
};
